/* eslint-disable react/no-danger */
import { faGithub } from "@fortawesome/free-brands-svg-icons";
import { faLink } from "@fortawesome/free-solid-svg-icons";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { graphql, Link } from "gatsby";
import { OutboundLink } from "gatsby-plugin-gtag";
import PropTypes from "prop-types";
import React from "react";
import ComplexWrapper from "../components/containers/complexWrapper";
import Wrapper from "../components/containers/wrapper";
import Tech from "../components/tech/tech";
import "../styles/tooltips.scss";

const Template = ({ data }) => {
  const {
    post: {
      excerpt,
      html,
      frontmatter: { link, source, title, date, tech, previewImage },
    },
  } = data;
  const postLink = link ? (
    <OutboundLink href={link} tooltip="Check it out!">
      <FontAwesomeIcon icon={faLink} className={`link`} />
    </OutboundLink>
  ) : (
    <></>
  );
  const postSource = source ? (
    <OutboundLink href={source} tooltip="Clone it!">
      <FontAwesomeIcon icon={faGithub} className={`link`} />
    </OutboundLink>
  ) : (
    <></>
  );
  const links =
    source || link ? (
      <span className={"links"}>
        {postLink}
        {postSource}
      </span>
    ) : (
      <></>
    );
  const image = previewImage ? previewImage.childImageSharp.fixed : null;
  return (
    <Wrapper title={title} description={excerpt} image={image}>
      <ComplexWrapper>
        <Link to="/projects">back</Link>
        <article>
          <h1>{title}</h1>
          {links}
          <time className={"date"}>
            {date}
            <Tech techs={tech} />
          </time>
          <div
            className="blog-post-content"
            dangerouslySetInnerHTML={{ __html: html }}
          />
        </article>
      </ComplexWrapper>
    </Wrapper>
  );
};

Template.propTypes = {
  data: PropTypes.any.isRequired,
};

export default Template;

export const pageQuery = graphql`
  query ProjectPostQuery($slug: String!) {
    post: markdownRemark(fields: { slug: { eq: $slug } }) {
      html
      excerpt(pruneLength: 200)
      frontmatter {
        title
        date(formatString: "MMMM, YYYY")
        tech
        link
        source
        previewImage {
          childImageSharp {
            fixed(width: 1200) {
              ...GatsbyImageSharpFixed
            }
            # resize(width: 1200) {
            #   src
            #   height
            #   width
            # }
          }
        }
      }
    }
  }
`;
